     1→/**
     2→ * Graph Data Processor
     3→ * Transforms notes, tasks, and their relationships into graph data for visualization
     4→ */
     5→
     6→import type { Note } from '../types/notes';
     7→
     8→export interface GraphNode {
     9→  id: string;
    10→  type: 'note' | 'tag';
    11→  label: string;
    12→  color: string; // Semantic color token
    13→  size: number; // Based on connection count
    14→  connections?: number; // P1: Connection count for tooltips
    15→  metadata: {
    16→    createdAt?: string;
    17→    folder?: string;
    18→    tags?: string[];
    19→  };
    20→}
    21→
    22→/**
    23→ * GraphNode with D3 simulation properties
    24→ * D3 adds x, y, vx, vy, fx, fy during force simulation
    25→ */
    26→export interface SimulationNode extends GraphNode {
    27→  x?: number;
    28→  y?: number;
    29→  vx?: number;
    30→  vy?: number;
    31→  fx?: number | null;
    32→  fy?: number | null;
    33→}
    34→
    35→export interface GraphEdge {
    36→  source: string; // Node ID
    37→  target: string; // Node ID
    38→  type: 'backlink' | 'tag';
    39→  strength: number; // For force simulation
    40→}
    41→
    42→/**
    43→ * GraphEdge after D3 simulation processes it
    44→ * D3 replaces source/target string IDs with actual node objects
    45→ */
    46→export interface SimulationEdge {
    47→  source: SimulationNode;
    48→  target: SimulationNode;
    49→  type: 'backlink' | 'tag';
    50→  strength: number;
    51→}
    52→
    53→export interface GraphData {
    54→  nodes: GraphNode[];
    55→  edges: GraphEdge[];
    56→}
    57→
    58→export interface GraphFilters {
    59→  searchQuery?: string;
    60→  selectedTags?: string[];
    61→  selectedFolders?: string[];
    62→  hideOrphans?: boolean;
    63→  focusNodeId?: string;
    64→  focusDepth?: number; // 1-3 hops from focused node
    65→  colorBy?: 'folder' | 'tag' | 'none'; // P1: Color grouping
    66→  sizeByConnections?: boolean; // P1: Node sizing (default: true)
    67→}
    68→
    69→/**
    70→ * P1: Generate color palette for graph node groups
    71→ * Returns HSL colors with good visual separation
    72→ */
    73→function generateColorPalette(count: number): string[] {
    74→  const colors: string[] = [];
    75→  const saturation = 70;
    76→  const lightness = 55;
    77→
    78→  for (let i = 0; i < count; i++) {
    79→    // Distribute hues evenly around color wheel
    80→    const hue = (i * 360) / count;
    81→    colors.push(`hsl(${hue}, ${saturation}%, ${lightness}%)`);
    82→  }
    83→
    84→  return colors;
    85→}
    86→
    87→/**
    88→ * P1: Assign colors to nodes based on grouping strategy
    89→ */
    90→function assignNodeColors(
    91→  nodes: GraphNode[],
    92→  colorBy: 'folder' | 'tag' | 'none'
    93→): Map<string, string> {
    94→  const colorMap = new Map<string, string>();
    95→
    96→  if (colorBy === 'none') {
    97→    // Use default semantic colors
    98→    return colorMap;
    99→  }
   100→
   101→  if (colorBy === 'folder') {
   102→    // Group by folder
   103→    const folders = new Set<string>();
   104→    nodes.forEach((node) => {
   105→      if (node.type === 'note') {
   106→        const folder = node.metadata.folder || 'root';
   107→        folders.add(folder);
   108→      }
   109→    });
   110→
   111→    const folderArray = Array.from(folders).sort();
   112→    const palette = generateColorPalette(folderArray.length);
   113→
   114→    folderArray.forEach((folder, index) => {
   115→      colorMap.set(folder, palette[index]);
   116→    });
   117→
   118→    return colorMap;
